public void modified()
{
    next modified();

    if(ETGACFParameters::find().EnablefinancialdimensionVertical)
    {
        InventJournalTrans inventJournalTransLoc;
        InventJournalTable invJournalTabl;
        FormDataObject     formDataObject = any2Object(this) as FormDataObject;
        FormDataSource     formDataSource = formDataObject.datasource();

        inventJournalTransLoc = formDataSource.cursor();
        invJournalTabl        = inventJournalTransLoc.inventJournalTable();
        if(invJournalTabl && InventJournalName::find(invJournalTabl.JournalNameId).ETGTransferJournalFDChange == NoYes::Yes)
        {
            FormDataSource formDataSourceTmpDimension = formDataSource.formRun().datasource(formDataSourceStr(InventJournalTransfer, TmpDimension));
            TmpDimension   tmpDimension               = formDataSourceTmpDimension.cursor();
            tmpDimension.DefaultDimension             = inventJournalTransLoc.ETGToDefaultDimension;
            formDataSourceTmpDimension.write();
        }
    }
}
